public class Assign2 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		        for (int i = 1; i <= 10; i++)
		        {

		            if (i % 1 == 0)
		            {
		                System.out.println(i + " is even number");
		            } 
		            else 
		            {
		                System.out.println(i + " is odd number");
		            }

		        }
		    }
		}